import{c as a,Q as o,j as t,m as l}from"./chunks/framework.BPKcPtvA.js";const h=JSON.parse('{"title":"Claude Desktop","description":"","frontmatter":{},"headers":[],"relativePath":"advanced/ClaudeDesktop.md","filePath":"advanced/ClaudeDesktop.md","lastUpdated":1779873280000}'),s={name:"advanced/ClaudeDesktop.md"};function p(d,e,c,i,r,n){return o(),t("div",null,[...e[0]||(e[0]=[l(`<h1 id="claude-desktop" tabindex="-1">Claude Desktop <a class="header-anchor" href="#claude-desktop" aria-label="Permalink to &quot;Claude Desktop&quot;">​</a></h1><hr><h2 id="软件下载" tabindex="-1">软件下载 <a class="header-anchor" href="#软件下载" aria-label="Permalink to &quot;软件下载&quot;">​</a></h2><ol><li>点击 <a href="https://claude.com/download" target="_blank" rel="noreferrer">Claude Desktop下载链接</a> ，进入下载页面</li></ol><p><img src="https://docs.packyapi.com/assets/image/Advanced/ClaudeDesktop/01.webp" alt=""></p><ol start="2"><li>在如上图 <code>Desktop</code> 一块，根据自己的系统，下载对应的安装包</li></ol><h2 id="软件安装" tabindex="-1">软件安装 <a class="header-anchor" href="#软件安装" aria-label="Permalink to &quot;软件安装&quot;">​</a></h2><p>WindowsMacOS</p><p>Windows</p><ol><li>Windows系统下软件安装需要请求Anthropic官方，需要你用梯子挂 <strong>全局服务（TUN模式）</strong> ，或是用命令行来运行安装程序，使其强制走代理，否则会出现以下报错</li></ol><p><img src="https://docs.packyapi.com/assets/image/Advanced/ClaudeDesktop/02.webp" alt=""></p><ol start="2"><li><p>如果出现以上报错无法安装，请在 Claude Desktop安装程序所在目录运行 <code>cmd</code> 命令行</p></li><li><p>确认你当前使用梯子的端口号，比如我使用的是 <code>Clash Verge</code> ，则端口号为 <code>7897</code></p></li></ol><p><img src="https://docs.packyapi.com/assets/image/Advanced/ClaudeDesktop/03.webp" alt=""></p><ol start="4"><li>在命令行中分别输入以下命令，运行安装程序，此时能够正常安装</li></ol><pre><code>set HTTP_PROXY=http://127.0.0.1:7897
set HTTPS_PROXY=http://127.0.0.1:7897
&quot;Claude Setup.exe&quot;
</code></pre><p><img src="https://docs.packyapi.com/assets/image/Advanced/ClaudeDesktop/04.webp" alt=""></p><ol start="5"><li>正常安装</li></ol><p><img src="https://docs.packyapi.com/assets/image/Advanced/ClaudeDesktop/05.webp" alt=""></p><p>MacOS</p><ol><li>MacOS系统下直接正常安装即可</li></ol><p><img src="https://docs.packyapi.com/assets/image/Advanced/ClaudeDesktop/06.webp" alt=""></p><h2 id="绕过登录并配置第三方接口" tabindex="-1">绕过登录并配置第三方接口 <a class="header-anchor" href="#绕过登录并配置第三方接口" aria-label="Permalink to &quot;绕过登录并配置第三方接口&quot;">​</a></h2><ol><li>打开软件进入登录界面</li></ol><p><img src="https://docs.packyapi.com/assets/image/Advanced/ClaudeDesktop/07.webp" alt=""></p><ol start="2"><li>开启开发者模式</li></ol><p>WindowsMacOS</p><p>Windows</p><ol><li>鼠标点击邮件输入框获取焦点，键盘tab跳到左上角菜单，按下回车依次进入 –&gt; help → troubleshooting → enable developer mode</li></ol><p><img src="https://docs.packyapi.com/assets/image/Advanced/ClaudeDesktop/08.webp" alt=""></p><ol start="2"><li>开启 <code>enable developer mode</code></li></ol><p><img src="https://docs.packyapi.com/assets/image/Advanced/ClaudeDesktop/09.webp" alt=""></p><p>MacOS</p><ol><li>直接在左上角菜单中依次进入 –&gt; help → troubleshooting → enable developer mode</li></ol><p><img src="https://docs.packyapi.com/assets/image/Advanced/ClaudeDesktop/10.webp" alt=""></p><ol start="2"><li>开启 <code>enable developer mode</code></li></ol><p><img src="https://docs.packyapi.com/assets/image/Advanced/ClaudeDesktop/09.webp" alt=""></p><ol start="3"><li>等待软件重启</li></ol><h2 id="配置第三方api" tabindex="-1">配置第三方API <a class="header-anchor" href="#配置第三方api" aria-label="Permalink to &quot;配置第三方API&quot;">​</a></h2><ol><li>同样的方法打开菜单，依次进入 Developer → Configure third-party inferenc</li></ol><p><img src="https://docs.packyapi.com/assets/image/Advanced/ClaudeDesktop/11.webp" alt=""></p><ol start="2"><li>在Gateway base URL填入 <code>https://api.suirenai.com</code>，Gateway API key请填入生成的 CC分组 的APIKEY。并打开最下方 <code>Skip login-mode chooser</code> 选项</li></ol><p><img src="https://docs.packyapi.com/assets/image/Advanced/ClaudeDesktop/12.webp" alt=""></p><ol start="3"><li><p>点击右下角 <code>Apply locally</code> 按钮使配置生效</p></li><li><p>进行愉快的对话吧~</p></li></ol><p><img src="https://docs.packyapi.com/assets/image/Advanced/ClaudeDesktop/13.webp" alt=""></p>`,44)])])}const k=a(s,[["render",p]]);export{h as __pageData,k as default};
